import{_ as a,o,c as i,ag as t}from"./chunks/framework.BO1WGGxE.js";const p=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md"}'),l={name:"changelog.md"};function r(n,e,s,d,c,h){return o(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>All notable changes to TypeORM Scopes will be documented here.</p><h2 id="_1-0-1-2026-04-05" tabindex="-1">[1.0.1] - 2026-04-05 <a class="header-anchor" href="#_1-0-1-2026-04-05" aria-label="Permalink to &quot;[1.0.1] - 2026-04-05&quot;">​</a></h2><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><code>relationScopes</code> support for applying scopes on related entities by relation path</li><li>Support for list syntax in relation scopes, for example <code>role: [&#39;activeOnly&#39;, &#39;adminOnly&#39;]</code></li><li>Support for function scopes in relation scope lists, for example <code>{ method: [&#39;byTenant&#39;, 10] }</code></li><li>Integration test coverage for relation scope list behavior</li></ul><h3 id="documentation" tabindex="-1">Documentation <a class="header-anchor" href="#documentation" aria-label="Permalink to &quot;Documentation&quot;">​</a></h3><ul><li>Added relation scopes documentation in API pages</li><li>Added advanced examples for relation scope lists</li><li>Updated guides and homepage examples to show multi-scope relation lists</li></ul><h2 id="_1-0-0-2026-02-27" tabindex="-1">[1.0.0] - 2026-02-27 <a class="header-anchor" href="#_1-0-0-2026-02-27" aria-label="Permalink to &quot;[1.0.0] - 2026-02-27&quot;">​</a></h2><h3 id="added-1" tabindex="-1">Added <a class="header-anchor" href="#added-1" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Initial stable release</li><li><code>@Scopes</code> decorator for defining named scopes</li><li><code>@DefaultScope</code> decorator for default query filters</li><li><code>ScopedRepository</code> class with scope methods</li><li><code>getScopedRepository</code> helper function</li><li>Support for all TypeORM find options (where, select, relations, order, etc.)</li><li>Function scopes with parameters</li><li>Scope merging and composition</li><li>Type-safe scope names (optional second generic parameter)</li><li><code>unscoped()</code> method to remove default scope</li><li>Comprehensive documentation and examples</li></ul><h3 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h3><ul><li><strong>Named Scopes</strong>: Define reusable query patterns</li><li><strong>Default Scopes</strong>: Automatic filters applied to all queries</li><li><strong>Function Scopes</strong>: Dynamic scopes with runtime parameters</li><li><strong>Scope Composition</strong>: Combine multiple scopes</li><li><strong>Type Safety</strong>: Full TypeScript support with autocomplete</li><li><strong>TypeORM Compatible</strong>: Works with existing TypeORM entities</li></ul><h3 id="documentation-1" tabindex="-1">Documentation <a class="header-anchor" href="#documentation-1" aria-label="Permalink to &quot;Documentation&quot;">​</a></h3><ul><li>Getting started guide</li><li>API reference</li><li>Usage examples</li><li>NestJS integration guide</li></ul><h2 id="unreleased" tabindex="-1">[Unreleased] <a class="header-anchor" href="#unreleased" aria-label="Permalink to &quot;[Unreleased]&quot;">​</a></h2><h3 id="planned" tabindex="-1">Planned <a class="header-anchor" href="#planned" aria-label="Permalink to &quot;Planned&quot;">​</a></h3><ul><li>Additional scope utilities</li><li>Performance optimizations</li><li>More examples and use cases</li><li>Community feedback integration</li></ul><hr><h2 id="version-history" tabindex="-1">Version History <a class="header-anchor" href="#version-history" aria-label="Permalink to &quot;Version History&quot;">​</a></h2><ul><li><strong>1.0.1</strong> - Relation scope lists and docs update (2026-04-05)</li><li><strong>1.0.0</strong> - Initial stable release (2026-02-27)</li></ul><h2 id="upgrade-guide" tabindex="-1">Upgrade Guide <a class="header-anchor" href="#upgrade-guide" aria-label="Permalink to &quot;Upgrade Guide&quot;">​</a></h2><h3 id="from-nothing-to-1-0-0" tabindex="-1">From Nothing to 1.0.0 <a class="header-anchor" href="#from-nothing-to-1-0-0" aria-label="Permalink to &quot;From Nothing to 1.0.0&quot;">​</a></h3><p>This is the first release. See <a href="/typeorm-query-scopes/guide/getting-started.html">Getting Started</a> for installation and usage.</p><h2 id="breaking-changes" tabindex="-1">Breaking Changes <a class="header-anchor" href="#breaking-changes" aria-label="Permalink to &quot;Breaking Changes&quot;">​</a></h2><p>None yet - this is the first release.</p><h2 id="deprecations" tabindex="-1">Deprecations <a class="header-anchor" href="#deprecations" aria-label="Permalink to &quot;Deprecations&quot;">​</a></h2><p>None yet.</p><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="https://github.com/aramyounis/typeorm-query-scopes/releases" target="_blank" rel="noreferrer">GitHub Releases</a></li><li><a href="/typeorm-query-scopes/contributing.html">Contributing Guide</a></li><li><a href="/typeorm-query-scopes/guide/migration.html">Migration Guide</a></li></ul>',29)])])}const g=a(l,[["render",r]]);export{p as __pageData,g as default};
